const h=document.querySelector('header'),m=document.querySelector('.mobile'),b=document.querySelector('.menuBtn');addEventListener('scroll',()=>h.classList.toggle('scrolled',scrollY>20));b&&b.addEventListener('click',()=>m.classList.toggle('open'));document.querySelectorAll('.fade').forEach(el=>new IntersectionObserver(es=>es.forEach(e=>{if(e.isIntersecting)e.target.classList.add('visible')}),{threshold:.12}).observe(el));const f=document.querySelector('#contactForm');if(f){const s=new URLSearchParams(location.search).get('subject');if(s)f.sujet.value=s;f.addEventListener('submit',e=>{e.preventDefault();const d=new FormData(f),body=`Prénom: ${d.get('prenom')}\nNom: ${d.get('nom')}\nEntreprise: ${d.get('entreprise')}\nEmail: ${d.get('email')}\nTéléphone: ${d.get('telephone')}\n\n${d.get('message')}`;location.href=`mailto:clement@integraleacademy.com?subject=${encodeURIComponent(d.get('sujet'))}&body=${encodeURIComponent(body)}`})}
